.LeftSideNav.slide-in {
  -webkit-animation: slide-in 0.3; /* Safari 4.0 - 8.0 */
  animation: slide-in 0.3;
  left: 0px;
  position: fixed;
  z-index: 9999;
}

@keyframes slide-in {
  0% {
    left: -200px;
  }
  100% {
    left: 0px;
  }
}

