


















































.MiddleSlider {
    background: url('~@/assets/imgs/bg.png');
    background-size: contain;
    width: 100%;
    height: 235px;
    .more {
        position: absolute;
        color: white;
        font-size: 0.8rem;
        font-weight: 300;
        right: 17px;
        padding-top: 10px;
        letter-spacing: 1px;
    }
    img {
        height: 150px;
        width: 150px;
    }
    h2 {
        width: 100%; 
        text-align: center; 
        border-bottom: 1px solid white; 
        line-height: 0.1em;
        margin: 10px 0 20px; 
        color: white;
        position: relative;
        top: 20px;
        padding-top: 5px;
    }
    h2 span { 
        background:#283068; 
        padding:0 10px; 
        font-size: 1rem;
        position: relative;
        top: -3px;
    }
    .slider {
        position: relative;
        top: 28px;
        max-width: 100%;
    }
}
